import envelope from './envelope.png';
import globePointer from './globe-pointer.png';
import houseChimney from './house-chimney.png';
import lock from './lock.png';
import marker from './marker.png';
import memberList from './member-list.png';
import phoneCall from './phone-call.png';
import shieldKeyhole from './shield-keyhole.png';
import signOutAlt from './sign-out-alt.png';
