/** Shared raster icons for use across the app (import URLs from here). */
const icons = {
  bolt,
  boxOpen,
  broom,
  cartShoppingFast,
  checkCircle,
  clipboardList,
  customize,
  diamondExclamation,
  envelope,
  globePointer,
  houseChimney,
  lock,
  marker,
  memberList,
  phoneCall,
  shieldKeyhole,
  signOutAlt,
  temperatureFrigid,
  tools,
  visit,
  windowFrame,
  wind,
};

export default icons;
